public class Dog {
    // Instance fields
    String name;
    int age;
    String breed;

    // Constructor
    public Dog(String name, int age, String breed) {
        this.name = name;
        this.age = age;
        this.breed = breed;
    }

    // Instance method
    public void bark() {
        System.out.println(name + " says: Woof!");
    }

    public String toString() {
        return name + " (" + breed + ", age " + age + ")";
    }

    public static void main(String[] args) {
        // Create objects using 'new'
        Dog d1 = new Dog("Buddy", 3, "Labrador");
        Dog d2 = new Dog("Max", 5, "Poodle");

        d1.bark();
        d2.bark();

        System.out.println(d1);  // calls toString()

        // d1 and d3 reference the SAME object
        Dog d3 = d1;
        d3.name = "Rocky";
        System.out.println(d1.name); // Rocky — same object!

        // Null reference
        Dog d4 = null;
        // d4.bark(); // NullPointerException!
    }
}

// Interface with abstract and default methods
public interface Shape {
    // Abstract method — must implement
    double area();
    double perimeter();

    // Default method — optional to override
    default String describe() {
        return String.format("Shape: area=%.2f, perimeter=%.2f", area(), perimeter());
    }

    // Static utility method
    static boolean isLarger(Shape a, Shape b) {
        return a.area() > b.area();
    }
}

// Implementing the interface
public class Circle implements Shape {
    private final double radius;

    public Circle(double radius) {
        this.radius = radius;
    }

    @Override
    public double area() {
        return Math.PI * radius * radius;
    }

    @Override
    public double perimeter() {
        return 2 * Math.PI * radius;
    }
}

