import java.util.*;

public class ListDemo {
    public static void main(String[] args) {
        // ArrayList — best for most use cases
        List<String> fruits = new ArrayList<>();
        fruits.add("Apple");
        fruits.add("Banana");
        fruits.add("Cherry");
        fruits.add(0, "Avocado"); // insert at index 0

        System.out.println(fruits);          // [Avocado, Apple, Banana, Cherry]
        System.out.println(fruits.get(2));   // Banana
        System.out.println(fruits.size());   // 4

        // Iterate safely while removing
        Iterator<String> it = fruits.iterator();
        while (it.hasNext()) {
            if (it.next().startsWith("A")) {
                it.remove(); // safe removal during iteration
            }
        }
        System.out.println(fruits); // [Banana, Cherry]

        // Immutable list (Java 9+)
        List<Integer> nums = List.of(1, 2, 3, 4, 5);
        System.out.println(nums);
        // nums.add(6); // UnsupportedOperationException!

        // LinkedList as a Deque
        Deque<String> deque = new LinkedList<>();
        deque.addFirst("First");
        deque.addLast("Last");
        System.out.println(deque.peekFirst()); // First
    }
}

import java.util.*;
import java.util.stream.*;

public class StreamDemo {
    public static void main(String[] args) {
        List<String> names = List.of(
            "Alice", "Bob", "Charlie", "Anna", "Brian", "alice"
        );

        // filter + map + distinct + sorted + collect
        List<String> result = names.stream()
            .filter(n -> n.length() > 3)          // keep names > 3 chars
            .map(String::toLowerCase)              // to lowercase
            .distinct()                            // remove duplicates
            .sorted()                              // alphabetical
            .collect(Collectors.toList());

        System.out.println(result);

        // flatMap example
        List<List<Integer>> nested = List.of(
            List.of(1, 2, 3),
            List.of(4, 5),
            List.of(6, 7, 8, 9)
        );

        List<Integer> flat = nested.stream()
            .flatMap(Collection::stream)    // flatten nested lists
            .filter(n -> n % 2 == 0)       // keep even numbers
            .collect(Collectors.toList());

        System.out.println(flat);

        // Numeric stream
        int sumOfSquares = IntStream.rangeClosed(1, 5)
            .map(n -> n * n)
            .sum();
        System.out.println("Sum of squares 1-5: " + sumOfSquares);
    }
}

import java.util.concurrent.*;
import java.util.*;

public class ExecutorDemo {
    public static void main(String[] args) throws Exception {

        // Fixed thread pool with 3 threads
        ExecutorService pool = Executors.newFixedThreadPool(3);

        try {
            // Submit Callable tasks that return results
            List<Future<Integer>> futures = new ArrayList<>();

            for (int i = 1; i <= 5; i++) {
                final int taskId = i;
                Future<Integer> future = pool.submit(() -> {
                    System.out.println("Task " + taskId + " on " +
                        Thread.currentThread().getName());
                    Thread.sleep(100); // simulate work
                    return taskId * taskId; // return result
                });
                futures.add(future);
            }

            // Collect results
            for (Future<Integer> f : futures) {
                System.out.println("Result: " + f.get()); // blocks until done
            }

        } finally {
            pool.shutdown();
            pool.awaitTermination(5, TimeUnit.SECONDS);
        }
    }
}

