import java.io.*;

public class ExceptionDemo {

    public static int divide(int a, int b) {
        try {
            return a / b;
        } catch (ArithmeticException e) {
            System.err.println("Cannot divide by zero: " + e.getMessage());
            return -1;
        } finally {
            System.out.println("divide() finally block executed");
        }
    }

    public static void readFile(String filename) {
        FileReader reader = null;
        try {
            reader = new FileReader(filename);
            // ... read file ...
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + filename);
        } catch (IOException e) {
            System.err.println("I/O error: " + e.getMessage());
        } finally {
            // Always close, even if exception occurred
            if (reader != null) {
                try { reader.close(); }
                catch (IOException e) { /* ignore close error */ }
            }
        }
    }

    // Multi-catch (Java 7+)
    public static void process(String input) {
        try {
            int value = Integer.parseInt(input);
            int[] arr = new int[value];
            arr[0] = 10;
        } catch (NumberFormatException | NegativeArraySizeException e) {
            System.err.println("Invalid input: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        System.out.println(divide(10, 2));
        System.out.println(divide(10, 0));
    }
}

import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

@DisplayName("Calculator Tests")
class CalculatorTest {

    private Calculator calc;

    @BeforeAll
    static void initAll() {
        System.out.println("Starting Calculator test suite");
    }

    @BeforeEach
    void setUp() {
        calc = new Calculator(); // fresh instance for each test
    }

    @Test
    @DisplayName("should add two positive numbers correctly")
    void testAddition() {
        // Arrange — setUp() already created calc
        // Act
        int result = calc.add(3, 5);
        // Assert
        assertEquals(8, result);
    }

    @Test
    @DisplayName("should throw ArithmeticException when dividing by zero")
    void testDivisionByZero() {
        ArithmeticException ex = assertThrows(
            ArithmeticException.class,
            () -> calc.divide(10, 0)
        );
        assertEquals("/ by zero", ex.getMessage());
    }

    @Test
    @DisplayName("should validate multiple operations together")
    void testMultipleAssertions() {
        assertAll("calculator operations",
            () -> assertEquals(5,  calc.add(2, 3)),
            () -> assertEquals(10, calc.multiply(2, 5)),
            () -> assertEquals(4,  calc.subtract(9, 5))
        );
    }

    @Test
    @Disabled("Feature not yet implemented")
    void testSquareRoot() {
        // Will be skipped
    }

    @AfterEach
    void tearDown() {
        calc = null;
    }

    @AfterAll
    static void tearDownAll() {
        System.out.println("Calculator test suite complete");
    }
}
